import {
  ChangeDetectionStrategy,
  Component,
  computed,
  forwardRef,
  input,
  model,
  output,
  signal,
} from '@angular/core';
import { ControlValueAccessor } from '@angular/forms';
import { injectFormControl } from '../../utils/form-control';
import { LabelComponent } from '../label';
import { COMBOBOX_CONTEXT, type ComboboxContext } from './combobox.tokens';

let _comboboxIdCounter = 0;

@Component({
  selector: 'n-combobox',
  standalone: true,
  imports: [LabelComponent],
  template: `
    <div class="flex flex-col" data-slot="root">

      @if (nLabel()) {
        <n-label [nId]="labelId()" [nRequired]="nRequired()" [nDisabled]="_isDisabled()">
          {{ nLabel() }}
        </n-label>
      }

      <ng-content />

      @if (nError() && hasError()) {
        <p
          [id]="errorId()"
          class="mt-1 text-xs text-destructive animate-error-in"
          role="alert"
          data-slot="error"
        >
          {{ nError() }}
        </p>
      }

      @if (nHint() && !hasError()) {
        <p
          [id]="hintId()"
          class="mt-1 text-xs text-muted-foreground"
          data-slot="hint"
        >
          {{ nHint() }}
        </p>
      }

    </div>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: { class: 'contents', 'data-slot': 'root' },
  providers: [
    {
      provide: COMBOBOX_CONTEXT,
      useFactory: (cmp: ComboboxComponent) => cmp.context,
      deps: [forwardRef(() => ComboboxComponent)],
    },
  ],
})
export class ComboboxComponent implements ControlValueAccessor {
  readonly nValue    = model<string>('');
  readonly nValues   = model<string[]>([]);
  readonly nMultiple = input<boolean>(false);
  readonly nDisabled = input<boolean>(false);
  readonly nLoading  = input<boolean>(false);
  readonly nClearable = input<boolean>(false);
  readonly nId       = input<string>('');

  readonly nLabel     = input<string>('');
  readonly nError     = input<string | null>(null);
  readonly nHint      = input<string | null>(null);
  readonly nRequired  = input<boolean>(false);
  readonly nAriaLabel = input<string>('');

  readonly nFilterChange = output<string>();

  private readonly _staticId   = `n-combobox-${++_comboboxIdCounter}`;
  private readonly _form       = injectFormControl<string | string[]>(this);
  private readonly _open       = signal(false);
  private readonly _query      = signal('');
  private readonly _activeId   = signal<string | null>(null);
  private readonly _triggerEl  = signal<HTMLElement | null>(null);
  // value -> label map populated by items, used to display the selected label
  // even when the value is set programmatically (form patch / reload).
  private readonly _labelMap = new Map<string, string>();
  private readonly _labelVersion = signal(0);
  // Set of item visibility predicates. A Set gives O(1) register/unregister
  // (the previous array spread was O(n²) on init); a version signal triggers
  // recomputation of visibleCount when the set membership changes.
  private readonly _visibilityFns = new Set<() => boolean>();
  private readonly _visVersion = signal(0);
  protected readonly _isDisabled = computed(() => this.nDisabled() || this._form.disabledByForm());
  private readonly _selectedLabel = computed(() => {
    this._labelVersion();
    return this._labelMap.get(this.nValue()) ?? '';
  });
  private readonly _visibleCount = computed(() => {
    this._visVersion();
    let n = 0;
    this._visibilityFns.forEach(fn => { if (fn()) n++; });
    return n;
  });
  private _navigateHandler: ((direction: 1 | -1) => void) | null = null;
  private _activeHandler: ((value: string | null) => void) | null = null;

  protected readonly comboboxId = computed(() => this.nId() || this._staticId);
  protected readonly labelId    = computed(() => `${this.comboboxId()}-label`);
  protected readonly errorId    = computed(() => `${this.comboboxId()}-error`);
  protected readonly hintId     = computed(() => `${this.comboboxId()}-hint`);

  protected readonly hasError = computed(
    () => !!this.nError() || (this._form.controlInvalid() && this._form.controlTouched()),
  );
  protected readonly isRequired  = computed(() => this.nRequired());
  protected readonly describedBy = computed<string | null>(() => {
    if (this.hasError()) return this.errorId();
    if (this.nHint())   return this.hintId();
    return null;
  });
  readonly context: ComboboxContext = {
    open: this._open,
    query: this._query.asReadonly(),
    multiple: this.nMultiple,
    disabled: this._isDisabled,
    loading: this.nLoading,
    clearable: this.nClearable,
    visibleCount: this._visibleCount,
    activeId: this._activeId.asReadonly(),
    value: this.nValue,
    values: this.nValues,
    selectedLabel: this._selectedLabel,
    triggerEl: this._triggerEl.asReadonly(),
    hasError:    this.hasError,
    required:    this.isRequired,
    describedBy: this.describedBy,
    labelId:     this.labelId,
    ariaLabel:   this.nAriaLabel,
    get triggerId() {
      return '';
    },
    get contentId() {
      return '';
    },
    openPanel: () => {
      // Reset the query on open (not on close) so the filtered list does not
      // reflow underneath the exit animation.
      this._query.set('');
      this._activeId.set(null);
      this._open.set(true);
    },
    closePanel: (returnFocus = true) => {
      this._open.set(false);
      this._form.notifyTouched();
      if (returnFocus) this._triggerEl()?.focus();
    },
    togglePanel: () => {
      if (this._open()) this.context.closePanel(false);
      else this.context.openPanel();
    },
    selectItem: (value, label) => {
      this._labelMap.set(value, label);
      this._labelVersion.update(v => v + 1);
      if (this.nMultiple()) {
        const current = this.nValues();
        const next = current.includes(value)
          ? current.filter(v => v !== value)
          : [...current, value];
        this.nValues.set(next);
        this._form.notifyChange(next);
      } else {
        this.nValue.set(value);
        this._form.notifyChange(value);
        this.context.closePanel(true);
      }
    },
    clearSelection: () => {
      if (this.nMultiple()) {
        this.nValues.set([]);
        this._form.notifyChange([]);
      } else {
        this.nValue.set('');
        this._form.notifyChange('');
      }
    },
    setQuery: (q) => {
      this._query.set(q);
      this.nFilterChange.emit(q);
    },
    setTriggerEl: (el) => this._triggerEl.set(el),
    isSelected: (value) =>
      this.nMultiple() ? this.nValues().includes(value) : this.nValue() === value,
    registerItemVisibility: (visible) => {
      this._visibilityFns.add(visible);
      this._visVersion.update(v => v + 1);
      return () => {
        this._visibilityFns.delete(visible);
        this._visVersion.update(v => v + 1);
      };
    },
    registerItemLabel: (value, label) => {
      // Labels are kept even after the item is destroyed (items only exist
      // while the overlay is attached) so the trigger keeps showing the
      // selected label after the panel closes. The map is bounded by the
      // number of distinct option values.
      this._labelMap.set(value, label);
      this._labelVersion.update(v => v + 1);
      return () => {};
    },
    navigateItems: (direction) => this._navigateHandler?.(direction),
    setNavigateHandler: (fn) => {
      this._navigateHandler = fn;
    },
    setActiveItem: (value) => this._activeHandler?.(value),
    setActiveHandler: (fn) => {
      this._activeHandler = fn;
    },
    setActiveId: (id) => this._activeId.set(id),
  };

  constructor() {
    Object.defineProperty(this.context, 'triggerId', { get: () => `${this.comboboxId()}-trigger` });
    Object.defineProperty(this.context, 'contentId', { get: () => `${this.comboboxId()}-content` });
  }

  writeValue(v: string | string[] | null | undefined): void {
    if (Array.isArray(v)) this.nValues.set(v);
    else this.nValue.set(v ?? '');
  }

  registerOnChange(fn: (v: string | string[]) => void): void {
    this._form.setOnChange(fn);
  }

  registerOnTouched(fn: () => void): void {
    this._form.setOnTouched(fn);
  }

  setDisabledState(isDisabled: boolean): void {
    this._form.setDisabledByForm(isDisabled);
  }
}

import {
  AfterViewInit,
  ChangeDetectionStrategy,
  Component,
  ElementRef,
  OnDestroy,
  computed,
  inject,
  input,
  viewChild,
} from '@angular/core';
import { mergeClasses } from '../../utils/merge-classes';
import { COMBOBOX_CONTEXT } from './combobox.tokens';
import { comboboxTriggerVariants, type ComboboxTriggerVariants } from './combobox.variants';

@Component({
  selector: 'n-combobox-trigger',
  standalone: true,
  template: `
    <div
      #triggerDiv
      [id]="ctx.triggerId"
      role="combobox"
      aria-haspopup="listbox"
      [attr.aria-expanded]="ctx.open()"
      [attr.aria-controls]="ctx.contentId"
      [attr.aria-busy]="ctx.loading() ? true : null"
      [attr.aria-disabled]="ctx.disabled() ? true : null"
      [attr.data-disabled]="ctx.disabled() ? '' : null"
      [attr.aria-labelledby]="ctx.labelId() || null"
      [attr.aria-label]="ctx.labelId() ? null : (ctx.ariaLabel() || null)"
      [attr.aria-invalid]="ctx.hasError() ? true : null"
      [attr.aria-required]="ctx.required() ? true : null"
      [attr.aria-describedby]="ctx.describedBy()"
      [attr.data-state]="ctx.open() ? 'open' : 'closed'"
      [class]="classes()"
      tabindex="0"
      (click)="handleClick()"
      (keydown)="handleTriggerKeydown($event)"
    >
      <span class="flex-1 truncate text-left" data-slot="value" [class.text-muted-foreground]="!hasValue()">
        {{ displayText() }}
      </span>

      <div class="ml-auto flex shrink-0 items-center gap-1">
        @if (ctx.clearable() && hasValue() && !ctx.loading()) {
          <button
            type="button"
            class="rounded-sm opacity-50 hover:opacity-100 focus:outline-none focus:ring-1 focus:ring-ring"
            aria-label="Clear selection"
            tabindex="-1"
            (click)="handleClear($event)"
          >
            <svg xmlns="http://www.w3.org/2000/svg" class="h-4 w-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true">
              <line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/>
            </svg>
          </button>
        }
        @if (ctx.loading()) {
          <svg class="h-4 w-4 animate-spin text-muted-foreground" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" aria-hidden="true">
            <circle class="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" stroke-width="4"/>
            <path class="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"/>
          </svg>
        } @else {
          <svg xmlns="http://www.w3.org/2000/svg" class="h-4 w-4 opacity-50" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true">
            <polyline points="6 9 12 15 18 9"/>
          </svg>
        }
      </div>
    </div>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: { class: 'contents' },
})
export class ComboboxTriggerComponent implements AfterViewInit, OnDestroy {
  readonly nSize = input<ComboboxTriggerVariants['nSize']>('default');
  readonly nPlaceholder = input<string>('Select an option...');
  readonly nClass = input<string>('');

  protected readonly ctx = inject(COMBOBOX_CONTEXT);

  private readonly _triggerDivRef = viewChild.required<ElementRef<HTMLElement>>('triggerDiv');

  protected readonly classes = computed(() =>
    mergeClasses(comboboxTriggerVariants({ nSize: this.nSize() }), this.nClass()),
  );

  protected readonly hasValue = computed(() =>
    this.ctx.multiple() ? this.ctx.values().length > 0 : !!this.ctx.value(),
  );

  protected readonly displayText = computed(() => {
    if (this.ctx.multiple()) {
      const count = this.ctx.values().length;
      return count > 0 ? `${count} selected` : this.nPlaceholder();
    }
    return this.ctx.selectedLabel() || this.ctx.value() || this.nPlaceholder();
  });

  ngAfterViewInit(): void {
    this.ctx.setTriggerEl(this._triggerDivRef().nativeElement);
  }

  ngOnDestroy(): void {
    this.ctx.setTriggerEl(null);
  }

  protected handleClick(): void {
    if (this.ctx.disabled()) return;
    this.ctx.togglePanel();
  }

  protected handleTriggerKeydown(event: KeyboardEvent): void {
    if (this.ctx.disabled()) return;
    if (!this.ctx.open()) {
      if (event.key === 'Enter' || event.key === ' ' || event.key === 'ArrowDown') {
        event.preventDefault();
        this.ctx.openPanel();
      }
    }
  }

  protected handleClear(event: Event): void {
    event.stopPropagation();
    this.ctx.clearSelection();
  }
}

import { ActiveDescendantKeyManager } from '@angular/cdk/a11y';
import {
  ConnectedPosition,
  Overlay,
  OverlayConfig,
  OverlayRef,
} from '@angular/cdk/overlay';
import { TemplatePortal } from '@angular/cdk/portal';
import {
  AfterViewInit,
  ChangeDetectionStrategy,
  Component,
  ElementRef,
  OnDestroy,
  TemplateRef,
  ViewContainerRef,
  computed,
  contentChildren,
  effect,
  inject,
  input,
  viewChild,
} from '@angular/core';
import { Subscription } from 'rxjs';
import { mergeClasses } from '../../utils/merge-classes';
import { ComboboxItemComponent } from './combobox-item.component';
import { COMBOBOX_CONTEXT } from './combobox.tokens';
import { comboboxContentVariants } from './combobox.variants';

type Side = 'top' | 'bottom' | 'left' | 'right';
type Align = 'start' | 'center' | 'end';

// Keep in sync with the data-[state=closed] exit animation duration in
// combobox.variants.ts so the overlay stays mounted while it animates out.
const EXIT_ANIMATION_MS = 150;

@Component({
  selector: 'n-combobox-content',
  standalone: true,
  template: `
    <ng-template #panel>
      <div
        #panelEl
        [id]="ctx.contentId"
        role="listbox"
        tabindex="-1"
        data-slot="content"
        [attr.aria-labelledby]="ctx.labelId() || ctx.triggerId"
        [attr.aria-multiselectable]="ctx.multiple() ? true : null"
        [attr.aria-activedescendant]="nSearch() ? null : (ctx.activeId() || null)"
        [attr.data-side]="nSide()"
        [attr.data-state]="ctx.open() ? 'open' : 'closed'"
        [class]="classes()"
        (keydown)="nSearch() ? null : handleKeydown($event)"
      >
        @if (nSearch()) {
          <div class="flex items-center gap-2 border-b px-3" data-slot="search">
            <svg xmlns="http://www.w3.org/2000/svg" class="h-4 w-4 shrink-0 opacity-50" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true">
              <circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/>
            </svg>
            <input
              #searchInput
              type="text"
              role="searchbox"
              aria-autocomplete="list"
              autocomplete="off"
              [attr.aria-controls]="ctx.contentId"
              [attr.aria-activedescendant]="ctx.activeId() || null"
              [value]="ctx.query()"
              [placeholder]="nSearchPlaceholder()"
              class="flex h-10 w-full bg-transparent py-3 text-sm outline-none placeholder:text-muted-foreground"
              (input)="handleSearchInput($event)"
              (keydown)="handleKeydown($event)"
            />
          </div>
        }
        <div class="max-h-60 overflow-y-auto p-1" data-slot="list">
          <ng-content />
        </div>
      </div>
    </ng-template>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: { class: 'contents' },
})
export class ComboboxContentComponent implements AfterViewInit, OnDestroy {
  readonly nSide = input<Side>('bottom');
  readonly nAlign = input<Align>('start');
  readonly nSideOffset = input<number>(4);
  readonly nAlignOffset = input<number>(0);
  readonly nSearch = input<boolean>(false);
  readonly nSearchPlaceholder = input<string>('Search...');
  readonly nClass = input<string>('');

  protected readonly ctx = inject(COMBOBOX_CONTEXT);
  private readonly _overlay = inject(Overlay);
  private readonly _vcr = inject(ViewContainerRef);

  protected readonly items = contentChildren(ComboboxItemComponent, { descendants: true });

  private readonly _panelTpl = viewChild.required<TemplateRef<unknown>>('panel');
  private readonly _panelElRef = viewChild<ElementRef<HTMLElement>>('panelEl');
  private readonly _searchInputRef = viewChild<ElementRef<HTMLInputElement>>('searchInput');

  private _overlayRef: OverlayRef | null = null;
  private _portal: TemplatePortal | null = null;
  private _keyManager: ActiveDescendantKeyManager<ComboboxItemComponent> | null = null;
  private _backdropSub?: Subscription;
  private _closeTimer: ReturnType<typeof setTimeout> | null = null;

  protected readonly classes = computed(() =>
    mergeClasses(comboboxContentVariants(), this.nClass()),
  );

  constructor() {
    effect(() => {
      if (this.ctx.open()) this.open();
      else this.scheduleClose();
    });
  }

  ngAfterViewInit(): void {
    this._portal = new TemplatePortal(this._panelTpl(), this._vcr);
  }

  ngOnDestroy(): void {
    if (this._closeTimer) clearTimeout(this._closeTimer);
    this.detach();
  }

  private open(): void {
    if (this._closeTimer) {
      clearTimeout(this._closeTimer);
      this._closeTimer = null;
    }
    if (!this._overlayRef?.hasAttached()) this.attach();
    queueMicrotask(() => {
      // Clear any stale hover highlight (the overlay can be reused if reopened
      // during the exit animation) and start with no active item.
      this.items().forEach(item => item.setInactiveStyles());
      this.initKeyManager();
      this.ctx.setActiveId(null);
      // Focus the search box when present, otherwise the listbox panel so
      // keyboard navigation works without a search input.
      const target = this.nSearch() ? this._searchInputRef() : this._panelElRef();
      target?.nativeElement.focus();
    });
  }

  private attach(): void {
    const trigger = this.ctx.triggerEl();
    if (!trigger || !this._portal) return;

    const width = trigger.getBoundingClientRect().width;
    const positions = this.buildPositions();
    const config = new OverlayConfig({
      width: width,
      positionStrategy: this._overlay
        .position()
        .flexibleConnectedTo(trigger)
        .withPositions(positions)
        .withFlexibleDimensions(false)
        .withPush(true),
      // Close the panel once the trigger scrolls out of view instead of
      // letting the options float over the page.
      scrollStrategy: this._overlay.scrollStrategies.reposition({ autoClose: true }),
      hasBackdrop: true,
      backdropClass: 'cdk-overlay-transparent-backdrop',
    });

    this._overlayRef = this._overlay.create(config);
    this._overlayRef.attach(this._portal);
    this._backdropSub = this._overlayRef.backdropClick().subscribe(() => this.ctx.closePanel(false));
    // autoClose detaches the overlay directly; keep our open state in sync.
    this._overlayRef.detachments().subscribe(() => {
      if (this.ctx.open()) {
        this.ctx.closePanel(false);
        this.detach();
      }
    });
  }

  // Fresh key manager each open so no item is pre-activated (no item shows the
  // highlight on open — it appears only on real hover or arrow navigation).
  private initKeyManager(): void {
    this._keyManager?.destroy();
    this._keyManager = new ActiveDescendantKeyManager<ComboboxItemComponent>(this.items())
      .withWrap()
      .skipPredicate((item: ComboboxItemComponent) => item.hidden() || item.nDisabled());
    this._keyManager.change.subscribe(() => this.syncActiveId());
    this.ctx.setNavigateHandler(direction => {
      if (direction === 1) this._keyManager!.setNextItemActive();
      else this._keyManager!.setPreviousItemActive();
    });
    this.ctx.setActiveHandler(value => {
      if (value == null) return;
      const index = this.items().findIndex(i => i.nValue() === value);
      if (index >= 0) this._keyManager?.updateActiveItem(index);
    });
  }

  /** Keep the panel mounted with data-state=closed so it can animate out. */
  private scheduleClose(): void {
    if (!this._overlayRef?.hasAttached() || this._closeTimer) return;
    this.ctx.setNavigateHandler(null);
    this.ctx.setActiveHandler(null);
    this.items().forEach(item => item.setInactiveStyles());
    this.ctx.setActiveId(null);
    this._closeTimer = setTimeout(() => {
      this._closeTimer = null;
      this.detach();
    }, EXIT_ANIMATION_MS);
  }

  private detach(): void {
    this._backdropSub?.unsubscribe();
    this._backdropSub = undefined;
    this.ctx.setNavigateHandler(null);
    this.ctx.setActiveHandler(null);
    this._keyManager?.destroy();
    this._keyManager = null;
    if (this._overlayRef?.hasAttached()) this._overlayRef.detach();
    this._overlayRef?.dispose();
    this._overlayRef = null;
  }

  private syncActiveId(): void {
    const active = this._keyManager?.activeItem;
    this.ctx.setActiveId(active ? active.itemId() : null);
  }

  protected handleSearchInput(event: Event): void {
    this.ctx.setQuery((event.target as HTMLInputElement).value);
    // Re-evaluate the active item after the list re-filters.
    queueMicrotask(() => {
      this._keyManager?.setFirstItemActive();
      this.syncActiveId();
    });
  }

  protected handleKeydown(event: KeyboardEvent): void {
    switch (event.key) {
      case 'ArrowDown':
        event.preventDefault();
        this._keyManager?.setNextItemActive();
        break;
      case 'ArrowUp':
        event.preventDefault();
        this._keyManager?.setPreviousItemActive();
        break;
      case 'Home':
        event.preventDefault();
        this._keyManager?.setFirstItemActive();
        break;
      case 'End':
        event.preventDefault();
        this._keyManager?.setLastItemActive();
        break;
      case 'Enter': {
        event.preventDefault();
        const active = this._keyManager?.activeItem;
        if (active && !active.nDisabled() && !active.hidden()) {
          this.ctx.selectItem(active.nValue(), active.getLabel());
        }
        break;
      }
      case 'Escape':
        event.preventDefault();
        this.ctx.closePanel(true);
        break;
      case 'Tab':
        this.ctx.closePanel(false);
        break;
    }
  }

  private buildPositions(): ConnectedPosition[] {
    const side = this.nSide();
    const align = this.nAlign();
    const sideOffset = this.nSideOffset();
    const alignOffset = this.nAlignOffset();

    const buildOne = (s: Side, a: Align): ConnectedPosition => {
      const isVertical = s === 'top' || s === 'bottom';
      const originY = s === 'bottom' ? 'bottom' : s === 'top' ? 'top' : 'center';
      const overlayY = s === 'bottom' ? 'top' : s === 'top' ? 'bottom' : 'center';
      const originX =
        s === 'right' ? 'end' : s === 'left' ? 'start' : a === 'center' ? 'center' : a;
      const overlayX =
        s === 'right' ? 'start' : s === 'left' ? 'end' : a === 'center' ? 'center' : a;
      return {
        originX: originX as ConnectedPosition['originX'],
        originY: originY as ConnectedPosition['originY'],
        overlayX: overlayX as ConnectedPosition['overlayX'],
        overlayY: overlayY as ConnectedPosition['overlayY'],
        offsetX: isVertical ? alignOffset : s === 'right' ? sideOffset : -sideOffset,
        offsetY: isVertical ? (s === 'bottom' ? sideOffset : -sideOffset) : alignOffset,
      };
    };

    const opposite: Record<Side, Side> = {
      top: 'bottom',
      bottom: 'top',
      left: 'right',
      right: 'left',
    };
    return [buildOne(side, align), buildOne(opposite[side], align)];
  }
}

import { Highlightable } from '@angular/cdk/a11y';
import {
  ChangeDetectionStrategy,
  Component,
  ElementRef,
  OnDestroy,
  afterNextRender,
  computed,
  inject,
  input,
  signal,
} from '@angular/core';
import { mergeClasses } from '../../utils/merge-classes';
import { COMBOBOX_CONTEXT } from './combobox.tokens';
import { comboboxItemVariants, type ComboboxItemVariants } from './combobox.variants';

@Component({
  selector: 'n-combobox-item',
  standalone: true,
  template: `
    <span class="flex w-4 shrink-0 items-center justify-center" aria-hidden="true">
      @if (isSelected()) {
        <svg xmlns="http://www.w3.org/2000/svg" class="h-4 w-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
          <polyline points="20 6 9 17 4 12"/>
        </svg>
      }
    </span>
    <ng-content />
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: {
    role: 'option',
    tabindex: '-1',
    'data-slot': 'item',
    '[id]': 'itemId()',
    '[class]': 'classes()',
    '[hidden]': 'hidden()',
    '[attr.aria-selected]': 'isSelected()',
    '[attr.aria-disabled]': 'nDisabled() ? true : null',
    '[attr.data-disabled]': 'nDisabled() ? "" : null',
    '[attr.data-highlighted]': 'highlighted() ? "" : null',
    '(click)': 'handleSelect()',
    '(mouseenter)': 'handleMouseEnter()',
    '(mouseleave)': 'setHighlighted(false)',
  },
})
export class ComboboxItemComponent implements Highlightable, OnDestroy {
  readonly nValue = input.required<string>();
  readonly nLabel = input<string>('');
  readonly nDisabled = input<boolean>(false);
  readonly nVariant = input<ComboboxItemVariants['nVariant']>('default');
  readonly nClass = input<string>('');

  readonly host = inject<ElementRef<HTMLElement>>(ElementRef);
  protected readonly ctx = inject(COMBOBOX_CONTEXT);
  private readonly _highlighted = signal(false);
  private readonly _unregister: () => void;

  readonly highlighted = this._highlighted.asReadonly();

  readonly itemId = computed(() => `${this.ctx.contentId}-opt-${this.nValue()}`);
  readonly isSelected = computed(() => this.ctx.isSelected(this.nValue()));
  readonly hidden = computed(() => {
    const q = this.ctx.query().toLowerCase();
    if (!q) return false;
    const label = (this.nLabel() || (this.host.nativeElement.textContent?.trim() ?? '')).toLowerCase();
    return !label.includes(q);
  });

  get disabled(): boolean {
    return this.nDisabled();
  }

  getLabel(): string {
    return this.nLabel() || (this.host.nativeElement.textContent?.trim() ?? '');
  }

  protected readonly classes = computed(() =>
    mergeClasses(comboboxItemVariants({ nVariant: this.nVariant() }), this.nClass()),
  );

  constructor() {
    this._unregister = this.ctx.registerItemVisibility(() => !this.hidden());
    // Register the value -> label mapping once the projected content has
    // rendered (the textContent fallback needs the DOM to exist).
    afterNextRender(() => this.ctx.registerItemLabel(this.nValue(), this.getLabel()));
  }

  ngOnDestroy(): void {
    this._unregister();
  }

  // --- Highlightable (ActiveDescendantKeyManager) -------------------------
  // Virtual focus: DOM focus stays on the search input; the active option is
  // highlighted via [data-highlighted] + aria-activedescendant.
  setActiveStyles(): void {
    this._highlighted.set(true);
    this.host.nativeElement.scrollIntoView({ block: 'nearest' });
  }

  setInactiveStyles(): void {
    this._highlighted.set(false);
  }

  setHighlighted(value: boolean): void {
    if (this.nDisabled()) return;
    this._highlighted.set(value);
  }

  protected handleMouseEnter(): void {
    if (this.nDisabled()) return;
    this._highlighted.set(true);
    this.ctx.setActiveItem(this.nValue());
  }

  protected handleSelect(): void {
    if (this.nDisabled()) return;
    this.ctx.selectItem(this.nValue(), this.getLabel());
  }
}

